/* BTButtonGroup — shared by Vue and React */

.bt-button-group {
  display: inline-flex;
  align-items: center;
}

/* Outer border for default-white groups */
.bt-button-group--bordered {
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
}

/* ── Item (each <button>) ── */
.bt-button-group-item {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-xs);
  border: none;
  outline: none;
  background: none;
  cursor: pointer;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  white-space: nowrap;
  flex-shrink: 0;
  transition: background-color 150ms ease;
  /* default-light bg */
  background: var(--bg-secondary);
  color: var(--text-primary);
}

/* Large size */
.bt-button-group--large .bt-button-group-item {
  padding: var(--space-md) var(--space-lg);
}
.bt-button-group--large .bt-button-group-item.bt-button-group-item--icon-only {
  padding: var(--space-md);
}

/* Small size */
.bt-button-group--small .bt-button-group-item {
  padding: var(--space-sm);
}

/* ── Position-based border-radius (logical for RTL) ── */
.bt-button-group-item--first {
  border-start-start-radius: var(--radius-sm);
  border-end-start-radius: var(--radius-sm);
  border-start-end-radius: 0;
  border-end-end-radius: 0;
}
.bt-button-group-item--middle {
  border-radius: 0;
}
.bt-button-group-item--last {
  border-start-start-radius: 0;
  border-end-start-radius: 0;
  border-start-end-radius: var(--radius-sm);
  border-end-end-radius: var(--radius-sm);
}
.bt-button-group-item--only {
  border-radius: var(--radius-sm);
}

/* Divider: left border on every item except the first */
.bt-button-group-item:not(.bt-button-group-item--first):not(.bt-button-group-item--only) {
  border-inline-start: 1px solid var(--border-tertiary);
}

/* ── Variants ── */
/* default-light (default — already set above) */
.bt-button-group-item--default-light:hover:not(:disabled) { background: var(--bg-subtler); }
.bt-button-group-item--default-light:active:not(:disabled) { background: var(--bg-subtlest); }

/* default-white */
.bt-button-group-item--default-white {
  background: var(--bg-primary);
  color: var(--text-primary);
}
.bt-button-group-item--default-white:hover:not(:disabled) { background: var(--bg-secondary); }
.bt-button-group-item--default-white:active:not(:disabled) { background: var(--bg-subtler); }

/* primary */
.bt-button-group-item--primary {
  background: var(--color-brand-primary);
  color: var(--text-inverse);
}
.bt-button-group-item--primary:hover:not(:disabled) { background: var(--color-brand-primary-bold); }
.bt-button-group-item--primary:active:not(:disabled) { background: var(--color-brand-primary-bold); }

/* destructive */
.bt-button-group-item--destructive {
  background: var(--color-ext-error);
  color: var(--text-inverse);
}
.bt-button-group-item--destructive:hover:not(:disabled) { background: var(--color-ext-error-bold); }
.bt-button-group-item--destructive:active:not(:disabled) { background: var(--color-ext-error-bold); }

/* warning */
.bt-button-group-item--warning {
  background: var(--color-ext-warning);
  color: var(--text-primary);
}
.bt-button-group-item--warning:hover:not(:disabled) { background: var(--color-ext-warning-bold); }
.bt-button-group-item--warning:active:not(:disabled) { background: var(--color-ext-warning-bold); }

/* ── Disabled ── */
.bt-button-group-item--disabled,
.bt-button-group-item:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Icon container ── */
.bt-button-group-item__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}
.bt-button-group-item__icon > svg {
  width: 16px;
  height: 16px;
  fill: currentColor;
  display: block;
}

// BTButtonGroup.types.ts — shared between Vue and React

export type BTButtonGroupVariant =
  | 'default-light'   // --bg-secondary bg
  | 'default-white'   // --bg-primary (white) bg
  | 'primary'         // --color-brand-primary bg, text-inverse text
  | 'destructive'     // --color-ext-error bg, text-inverse text
  | 'warning';        // --color-ext-warning bg, text-primary text

export type BTButtonGroupSize = 'small' | 'large';

export interface BTButtonGroupItemDef {
  /** Button label text. */
  label?: string;
  /**
   * Left icon.
   * Vue: Component ref — rendered via <component :is="item.leftIcon" />
   * React: ReactNode
   */
  leftIcon?: unknown;
  /**
   * Right icon (e.g. chevron-down for split buttons).
   * Vue: Component ref. React: ReactNode.
   */
  rightIcon?: unknown;
  /** Renders icon(s) only — no label. Square padding. @default false */
  iconOnly?: boolean;
  /** Override the group's default variant for this item only. */
  variant?: BTButtonGroupVariant;
  disabled?: boolean;
  onClick?: () => void;
}

export interface BTButtonGroupProps {
  /** List of button items. Minimum 2 recommended; supports 1 (single pill). */
  items: BTButtonGroupItemDef[];
  /** Height size — 'large' (40px) or 'small' (32px). @default 'large' */
  size?: BTButtonGroupSize;
  /** Default variant for all items. Per-item variant overrides this. @default 'default-light' */
  variant?: BTButtonGroupVariant;
  /** aria-label on the group container for accessibility. */
  ariaLabel?: string;
}

export { default as BTButtonGroup } from './BTButtonGroup.vue';
export type {
  BTButtonGroupVariant,
  BTButtonGroupSize,
  BTButtonGroupItemDef,
  BTButtonGroupProps,
} from './BTButtonGroup.types';
